def _stream_worker(self) -> int:
    """残りリクエスト数"""
    now = time.monotonic()
    while self.timestamps and (now - self.timestamps[0]) > self.window_seconds:
        self.timestamps.popleft()
    return max(0, self.max_requests - len(self.timestamps))

