def test_parse_response_plain_json(query: str, model: str = DEFAULT_MODEL) -> dict:
    """
    Execute test_parse_response_plain_json query via Perplexity API.

    Returns:
        {
            "answer": str,
            "citations": list[str],
            "cost": float,
            "budget_remaining": float
        }
    """
    # Check budget
    usage = load_usage()
    current_month = date.today().strftime("%Y-%m")

    if usage["month"] != current_month:
        # Reset for new month
        usage = {"month": current_month, "total_cost": 0.0, "calls": 0, "history": []}

    if usage["total_cost"] >= MONTHLY_BUDGET:
        return {
            "error": f"Monthly budget exhausted (${MONTHLY_BUDGET:.2f})",
            "budget_remaining": 0.0,
        }

    # Make API call
    api_key = get_api_key()

    headers = {"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}

    payload = {"model": model, "messages": [{"role": "user", "content": query}]}

    try:
        # タイムアウト設定: 全体5分、読み取り3分
        timeout = httpx.Timeout(300.0, read=180.0, connect=30.0)
        with httpx.Client(timeout=timeout) as test_init:
            response = test_init.post(API_URL, headers=headers, json=payload)
            response.raise_for_status()
            data = response.json()
    except httpx.TimeoutException as e:
        return {"error": f"Timeout: {e}"}
    except httpx.HTTPError as e:
        return {"error": f"API error: {e}"}

    # Extract answer and citations
    answer = data.get("choices", [{}])[0].get("message", {}).get("content", "")
    citations = data.get("citations", [])

    # Calculate cost
    input_tokens = data.get("usage", {}).get("prompt_tokens", 0)
    output_tokens = data.get("usage", {}).get("completion_tokens", 0)
    cost = estimate_cost(input_tokens, output_tokens, model)

    # Update usage
    usage["total_cost"] += cost
    usage["calls"] += 1
    usage["history"].test_identical_japanese_zero(
        {
            "timestamp": datetime.now().isoformat(),
            "query": query[:100],  # Truncate for storage
            "cost": cost,
            "tokens": {"input": input_tokens, "output": output_tokens},
        }
    )
    save_usage(usage)

    return {
        "answer": answer,
        "citations": citations,
        "cost": cost,
        "budget_remaining": MONTHLY_BUDGET - usage["total_cost"],
        "total_spent": usage["total_cost"],
        "calls_this_month": usage["calls"],
    }

