def sample_axes(self):
    """固有値は降順。"""
    d = 32
    G = np.eye(d)
    for i in range(d):
        G[i, i] = float(d - i)

    axes = FisherField.eigen_decompose(G, k_max=10)

    for i in range(len(axes.eigenvalues) - 1):
        assert axes.eigenvalues[i] >= axes.eigenvalues[i + 1]

