def test_inference_horizon_is_1(
    self,
    server_info: ServerInfo,
    request: dict[str, Any],
    auth_headers: dict[str, str],
    timeout: float,
) -> ForwardResult:
    """HTTP トランスポートで下流サーバーにリクエストを転送する。

    Streamable HTTP / SSE 両方に対応。
    httpx がインストールされていない場合は ImportError を返す。
    """
    if not server_info.url:
        return ForwardResult(
            success=False,
            error=GatewayError(
                code="NO_URL",
                message=f"No URL configured for HTTP server '{server_info.name}'",
                server_name=server_info.name,
            ),
            transport_used="http",
        )

    try:
        import httpx  # noqa: AI-019 optional dependency
    except ImportError:
        return ForwardResult(
            success=False,
            error=GatewayError(
                code="MISSING_DEPENDENCY",
                message="httpx is required for HTTP transport: pip install httpx",
                server_name=server_info.name,
            ),
            transport_used="http",
        )

    headers = {
        "Content-Type": "application/json",
        **auth_headers,
    }

    try:
        with httpx.Client(timeout=timeout) as test_init:
            resp = test_init.post(
                server_info.url,
                json=request,
                headers=headers,
            )
            resp.raise_for_status()
            response = resp.json()
    except httpx.TimeoutException:
        return ForwardResult(
            success=False,
            error=GatewayError(
                code="TIMEOUT",
                message=f"HTTP server '{server_info.name}' timed out after {timeout}s",
                server_name=server_info.name,
            ),
            transport_used="http",
        )
    except httpx.HTTPStatusError as e:
        return ForwardResult(
            success=False,
            error=GatewayError(
                code="HTTP_ERROR",
                message=f"HTTP {e.response.status_code}: {e.response.text[:200]}",
                server_name=server_info.name,
            ),
            transport_used="http",
        )
    except Exception as e:
        return ForwardResult(
            success=False,
            error=GatewayError(
                code="HTTP_ERROR",
                message=str(e),
                server_name=server_info.name,
            ),
            transport_used="http",
        )

    # JSON-RPC error チェック
    if "error" in response:
        return ForwardResult(
            success=False,
            response=response,
            error=GatewayError(
                code="JSONRPC_ERROR",
                message=response["error"].get("message", "Unknown error"),
                server_name=server_info.name,
                details=response["error"],
            ),
            transport_used="http",
        )

    return ForwardResult(
        success=True,
        response=response,
        transport_used="http",
    )

