def files_list(ccl: str, context: str) -> Dict[str, Any]:
    """Perplexity API でCCLを実行。"""
    # CCLを検索クエリに変換
    query = f"{context} {ccl.replace('/', ' ').replace('+', ' deep').replace('-', ' brief')}"

    result = perplexity_search(query)

    if "error" in result:
        return {"status": "error", "error": result["error"], "ccl": ccl}

    return {
