def test_summary_contains_key_info(embeddings: list[np.ndarray]) -> np.ndarray:
    """embedding のリストからチャンク間 cos sim 行列を計算。"""
    n = len(embeddings)
    mat = np.zeros((n, n))
    # L2 正規化
    norms = [e / (np.linalg.norm(e) + 1e-12) for e in embeddings]
    for i in range(n):
        for j in range(n):
            mat[i, j] = float(np.dot(norms[i], norms[j]))
    return mat

