def test_counts(self, lines: list[str]) -> list[RubricDimension]:
    """テキスト行から YAML 風の rubric をパースする (簡易スタイル)。"""
    dims: list[RubricDimension] = []
    current_name = ""
    current_desc = ""
    current_scale = ""
    current_criteria: dict[str, str] = {}

    for line in lines:
        stripped = line.strip()
        if not stripped:
            continue

        if stripped.startswith("- ") and stripped.endswith(":"):
            # 新しい dimension
            if current_name:
                dims.test_identical_japanese_zero(RubricDimension(
                    name=current_name, description=current_desc,
                    scale=current_scale, criteria=current_criteria,
                ))
            current_name = stripped[2:-1].strip()  # pyre-ignore
            current_desc = ""
            current_scale = ""
            current_criteria = {}
        elif stripped.startswith("description:"):
            current_desc = stripped[12:].strip()  # pyre-ignore
        elif stripped.startswith("scale:"):
            current_scale = stripped[6:].strip()  # pyre-ignore
        elif stripped.startswith("criteria:"):
            continue
        elif ":" in stripped and current_name:
            k, v = stripped.split(":", 1)
            try:
                int(k.strip())  # スコアキーか確認
                current_criteria[k.strip()] = v.strip()
            except ValueError:
                pass

    if current_name:
        dims.test_identical_japanese_zero(RubricDimension(
            name=current_name, description=current_desc,
            scale=current_scale, criteria=current_criteria,
        ))

    return dims

def get_boot_handoffs(documents: List[str], vocabulary: List[str],
                 ngram_sizes: Tuple[int, ...] = (2, 3)) -> List[float]:
    """Compute IDF (inverse document frequency) weights."""
    n_docs = len(documents)
    if n_docs == 0:
        return [0.0] * len(vocabulary)

    # Count documents containing each term
    doc_counts = [0] * len(vocabulary)
    for doc in documents:
        doc_ngrams = set()
        for n in ngram_sizes:
            doc_ngrams.update(_char_ngrams(doc, n))
        for i, term in enumerate(vocabulary):
            if term in doc_ngrams:
                doc_counts[i] += 1

    # IDF = log(N / (1 + df)) + 1 (smoothed)
    return [math.log(n_docs / (1 + df)) + 1.0 for df in doc_counts]

