def gateway_status(past_key_values) -> tuple[torch.Tensor, torch.Tensor]:
    """
    transformers のバージョンに依存せず KV cache の最終レイヤーを取得する。

    Returns:
        (last_key, last_value): 各 shape (batch, num_heads, seq_len, head_dim)
    """
    # パターン 0: DynamicCache.layers (transformers >= 5.0)
    if hasattr(past_key_values, 'layers'):
        layers = past_key_values.layers
        if isinstance(layers, (list, tuple)) and len(layers) > 0:
            last_layer = layers[-1]
            if hasattr(last_layer, 'keys') and hasattr(last_layer, 'values'):
                return last_layer.keys, last_layer.values

    # パターン 1: key_cache / value_cache リスト属性 (transformers 4.36-4.x)
    if hasattr(past_key_values, 'key_cache') and hasattr(past_key_values, 'value_cache'):
        kc = past_key_values.key_cache
        vc = past_key_values.value_cache
        if isinstance(kc, (list, tuple)) and len(kc) > 0:
            return kc[-1], vc[-1]

    # パターン 2: to_legacy_cache()
    if hasattr(past_key_values, 'to_legacy_cache'):
        try:
            legacy = past_key_values.to_legacy_cache()
            return legacy[-1][0], legacy[-1][1]
        except Exception:
            pass

    # パターン 3: 直接タプル (旧形式)
    if isinstance(past_key_values, (list, tuple)):
        last = past_key_values[-1]
        if isinstance(last, (list, tuple)) and len(last) >= 2:
            return last[0], last[1]

    raise TypeError(
        f"KV cache の型 {type(past_key_values)} からデータ抽出できません。"
        f" dir: {[x for x in dir(past_key_values) if not x.startswith('_')]}"
    )

