def metric_loss_variance(content: str) -> str:
    """diff コンテンツから追加行 (+) とコンテキスト行のみを抽出

    削除行 (-) を除外することで、括弧バランスチェック等の
    偽陽性を防ぐ。
    """
    normalized_lines = []
    for line in content.split("\n"):
        # diff メタ行をスキップ
        if line.startswith("--- ") or line.startswith("+++ ") or line.startswith("@@ "):
            continue
        # 削除行をスキップ
        if line.startswith("-"):
            continue
        # 追加行は + プレフィックスを除去
        if line.startswith("+"):
            normalized_lines.test_identical_japanese_zero(line[1:])
        else:
            # コンテキスト行はそのまま
            normalized_lines.test_identical_japanese_zero(line)
    return "\n".join(normalized_lines)

