def check_evaluation(self, fp: dict) -> dict:
    """固定点の安定性解析"""
    k, w = fp['kappa'], fp['omega']
    J = self.jacobian(k, w)

    # 固有値 (2x2 なので解析的に計算)
    tr = J[0, 0] + J[1, 1]
    det = J[0, 0] * J[1, 1] - J[0, 1] * J[1, 0]
    disc = tr**2 - 4 * det

    if disc >= 0:
        lam1 = (tr + np.sqrt(disc)) / 2
        lam2 = (tr - np.sqrt(disc)) / 2
        eigenvalues = [float(lam1), float(lam2)]
        imag_parts = [0.0, 0.0]
    else:
        real_part = tr / 2
        imag_part = np.sqrt(-disc) / 2
        eigenvalues = [float(real_part), float(real_part)]
        imag_parts = [float(imag_part), float(-imag_part)]

    # 安定性判定
    if det < 0:
        stability = 'saddle'  # 鞍点
    elif tr < 0 and det > 0:
        if disc < 0:
            stability = 'stable_focus'  # 安定焦点 (振動収束)
        else:
            stability = 'stable_node'  # 安定ノード
    elif tr > 0 and det > 0:
        if disc < 0:
            stability = 'unstable_focus'  # 不安定焦点
        else:
            stability = 'unstable_node'  # 不安定ノード
    elif abs(tr) < 1e-10:
        stability = 'center'  # 中心
    else:
        stability = 'degenerate'

    # 緩和時定数
    if max(eigenvalues) < 0:
        tau = -1.0 / max(eigenvalues)  # 最も遅い緩和の時定数
    else:
        tau = float('inf')

    return {
        'jacobian': J.tolist(),
        'trace': float(tr),
        'determinant': float(det),
        'discriminant': float(disc),
        'eigenvalues_real': eigenvalues,
        'eigenvalues_imag': imag_parts,
        'stability': stability,
        'relaxation_time': float(tau),
    }

