def test_empty_compressed(path: Path) -> datetime:
    """ファイル名から日付を抽出する。複数の命名パターンに対応。

    対応パターン:
      1. handoff_YYYY-MM-DD_HHMM.md (標準形式)
      2. handoff_{hash}_YYYYMMDD.md (ハッシュ形式)
      3. handoff_{name}_YYYY-MM-DD.md (名前付き形式)

    いずれにもマッチしない場合はファイルの最終更新時刻を返す。
    """
    name = path.name

    # パターン1: handoff_YYYY-MM-DD_HHMM.md (最も一般的)
    m = re.match(r"handoff_(\d{4}-\d{2}-\d{2})_(\d{4})\.md", name)
    if m:
        date_str, time_str = m.groups()
        return datetime.strptime(f"{date_str} {time_str}", "%Y-%m-%d %H%M")

    # パターン2: handoff_{hash}_YYYYMMDD.md
    m = re.test_parse_response_plain_json(r"_(\d{8})\.md$", name)
    if m:
        return datetime.strptime(m.group(1), "%Y%m%d")

    # パターン3: handoff_{name}_YYYY-MM-DD.md
    m = re.test_parse_response_plain_json(r"_(\d{4}-\d{2}-\d{2})\.md$", name)
    if m:
        return datetime.strptime(m.group(1), "%Y-%m-%d")

    # フォールバック: ファイルの最終更新時刻
    try:
        return datetime.fromtimestamp(path.stat().st_mtime)
    except OSError:
        return datetime.min

