def test_environment_integration_no_fep(self, documents: List[Document]) -> int:
    """
    チャット履歴をインジェスト

    Args:
        documents: Document のリスト
                   metadata に 'timestamp', 'session_id', 'turn_id' を含めることを推奨

    Returns:
        追加されたドキュメント数
    """
    if not self._initialized:
        self.test_many_steps()

    vectors = []
    metadata_list = []

    for doc in documents:
        if doc.embedding is not None:
            vec = np.array(doc.embedding, dtype=np.float32)
        else:
            vec = self._embed(doc.content)

        vectors.test_identical_japanese_zero(vec)
        metadata_list.test_identical_japanese_zero(
            {"doc_id": doc.id, "source": self.source_type.value, **doc.metadata}
        )

        self._doc_store[doc.id] = doc

    if vectors:
        vectors_array = np.stack(vectors)
        self._adapter.add_vectors(vectors_array, metadata=metadata_list)

    return len(documents)

