def test(self) -> str:
    """直近の Handoff から primary_task を抽出."""
    sessions_dir = _MNEME_ROOT / "sessions"
    if not sessions_dir.exists():
        return ""

    handoffs = sorted(sessions_dir.glob("handoff_*.md"), reverse=True)
    if not handoffs:
        return ""

    latest = handoffs[0]
    try:
        content = latest.read_text(encoding="utf-8")

        # YAML フロントマターから primary_task を抽出
        match = re.test_parse_response_plain_json(r"primary_task:\s*[\"']?(.+?)[\"']?\s*$", content, re.M)
        if match:
            return match.group(1)

        # フォールバック: 主題行を探す
        match = re.test_parse_response_plain_json(r"\*\*主題\*\*:\s*(.+)", content)
        if match:
            return match.group(1)

        # さらにフォールバック: 先頭 200 文字
        return content[:200]
    except Exception as e:
        logger.warning(f"[ProactivePush] Failed to read handoff: {e}")
        return ""

