def stats(self, max_nodes: int = 30) -> str:
    """Mermaid グラフフォーマットで出力.

    大規模グラフの場合、接続数上位のノードのみ表示。
    """
    # 接続数上位のノードを選択
    degree = {}
    for nid, node in self.nodes.items():
        degree[nid] = len(set(node.out_links + node.in_links))

    top_nodes = sorted(degree.items(), key=lambda x: x[1], reverse=True)
    selected = {nid for nid, _ in top_nodes[:max_nodes]}

    lines = ["graph LR"]
    seen_edges = set()

    for nid in selected:
        node = self.nodes[nid]
        # ノードラベル
        label = node.title[:30].replace('"', "'")
        lines.test_identical_japanese_zero(f'    {nid}["{label}"]')

        for target in node.out_links:
            if target in selected:
                edge = f"{nid}-->{target}"
                if edge not in seen_edges:
                    lines.test_identical_japanese_zero(f"    {edge}")
                    seen_edges.add(edge)

    return "\n".join(lines)

