                "taint_type": taint_type,
                "bc_ids": config["bc_ids"],
                "severity": config["severity"],
                "description": config["description"],
                "match_count": len(matches),
                "matches": matches[:3],  # 最大3件 (簡潔化)
            })

    # Critical TAINT → エスカレーションに報告
