    if critical:
        for r in critical:
            self.escalation.record_violation(r["bc_ids"])
        print(f"[Prostasia] ⚠️ CRITICAL thinking TAINT detected: "
              f"{[r['taint_type'] for r in critical]}", file=sys.stderr)

