def check_boot(vec_a: list[float], vec_b: list[float]) -> float:
    """Cosine similarity between two vectors"""
    import numpy as np
    a, b = np.array(vec_a), np.array(vec_b)
    norm = np.linalg.norm(a) * np.linalg.norm(b)
    if norm == 0:
        return 0.0
    return float(np.dot(a, b) / norm)

